testCases.script:
console.log('🚀 开始测试: 文件上传流程');

console.log('⏳ 步骤 1/8: 加载页面...');
await page.waitForLoadState('networkidle');
console.log('✓ 页面加载完成');

console.log('⏳ 步骤 2/8: 等待初始化...');
const dragger = page.locator('.ant-upload-drag');
await dragger.waitFor({ state: 'visible', timeout: 15000 });
console.log('✓ 上传区域已显示，初始化完成');

console.log('⏳ 步骤 3/8: 上传文件...');
const fileInput = page.locator('input[type="file"]');
await fileInput.setInputFiles(__assets + '/test-audio.mp3');
console.log('✓ 文件已选择');

console.log('⏳ 步骤 4/8: 等待文件信息显示...');
const fileNameEl = page.getByText(/test-audio/i);
await fileNameEl.waitFor({ state: 'visible', timeout: 10000 });
console.log('✓ 文件名已显示，进入配置步骤');
const fileName = await fileNameEl.textContent();
await capture('文件上传后 - 显示文件信息', {
  selector: 'getByText(/test-audio/i)',
  metadata: {
    elementText: fileName
  }
});

console.log('⏳ 步骤 5/8: 检查语言选择器...');
const langSelector = page.locator('[data-id]');
const langCount = await langSelector.count();
console.log('✓ 语言选择器已就绪 (找到 ' + langCount + ' 个选项)');

console.log('⏳ 步骤 6/8: 点击 Transcribe 按钮...');
const transcribeBtn = page.getByRole('button', { name: /transcribe|confirm/i });
await transcribeBtn.click();
console.log('✓ 已点击 Transcribe 按钮');

console.log('⏳ 步骤 7/8: 等待上传进度条...');
const progressBar = page.locator('[class*="progress"]').first();
await progressBar.waitFor({ state: 'visible', timeout: 10000 });
console.log('✓ 上传进度条已显示');
await capture('点击 Transcribe 后 - 显示进度条', {
  selector: '[class*="progress"]'
});

console.log('⏳ 步骤 8/8: 等待结果（成功/限制/错误）...');

const result = await Promise.race([
  page.waitForURL(
    u => u.href.includes('from=official') || u.href.includes('app.notta.ai'),
    { timeout: 90000 }
  ).then(() => 'success'),
  page.locator('[role="dialog"], [class*="dialog"]').waitFor({ state: 'visible', timeout: 90000 }).then(() => 'limit'),
  page.getByText(/error|failed|失败|错误/i).waitFor({ state: 'visible', timeout: 90000 }).then(() => 'error'),
]);

if (result === 'success') {
  console.log('✅ 成功: 已跳转到结果页');
  console.log('结果页 URL:', page.url());
  console.log('⏳ 等待页面加载完成（等待 order/summary 接口）...');
  try {
    await page.waitForResponse(
      response => response.url().includes('/v1/order/summary') && response.status() === 200,
      { timeout: 30000 }
    );
    console.log('✓ 页面数据加载完成');
  } catch (err) {
    console.log('⚠️  等待接口超时，直接等待固定时间');
  }
  await page.waitForTimeout(3000);
  await capture('最终结果 - 成功页面', {
    status: 'success',
    metadata: {
      networkRequest: '/v1/order/summary'
    }
  });
  assert(page.url().includes('from=official'), '应跳转到结果页');
} else if (result === 'limit') {
  console.log('⚠️  达到限制: 显示限制弹窗（IP 限制）');
  const dialogContent = await page.locator('[role="dialog"], [class*="dialog"]').textContent();
  console.log('弹窗内容:', dialogContent.substring(0, 200));
  await capture('最终结果 - 限制弹窗', {
    selector: '[role="dialog"]',
    status: 'warning',
    metadata: {
      elementText: dialogContent ? dialogContent.substring(0, 100) : ''
    }
  });
  const signUpBtn = page.getByRole('link', { name: /sign up/i });
  const hasSignUp = await signUpBtn.count() > 0;
  console.log('是否有注册按钮:', hasSignUp);
  assert(hasSignUp, '限制弹窗应有注册按钮');
  console.log('✅ 限制提示正常显示');
} else if (result === 'error') {
  console.log('❌ 出现错误提示');
  const errorText = await page.getByText(/error|failed|失败|错误/i).first().textContent();
  console.log('错误信息:', errorText);
  await capture('最终结果 - 错误提示', {
    status: 'error',
    metadata: {
      elementText: errorText
    }
  });
  assert(false, '上传过程中出现错误: ' + errorText);
}

console.log('🚀 开始测试: 粘贴链接流程');

console.log('⏳ 步骤 1/7: 加载页面...');
await page.waitForLoadState('networkidle');
console.log('✓ 页面加载完成');

console.log('⏳ 步骤 2/7: 等待初始化...');
const dragger = page.locator('.ant-upload-drag');
await dragger.waitFor({ state: 'visible', timeout: 15000 });
console.log('✓ 初始化完成');

console.log('⏳ 步骤 3/7: 切换到 Paste a link 标签...');
const pasteLinkTab = page.getByText(/paste a link/i);
await pasteLinkTab.click();
console.log('✓ 已切换到 Paste a link 标签');
await capture('切换到 Paste a link 标签', {
  selector: 'getByText(/paste a link/i)'
});

console.log('⏳ 步骤 4/7: 输入 YouTube 链接...');
const urlInput = page.locator('input[type="text"]');
await urlInput.waitFor({ state: 'visible', timeout: 5000 });
await urlInput.fill('https://www.youtube.com/watch?v=dQw4w9WgXcQ');
console.log('✓ 已输入 YouTube 链接');

console.log('⏳ 步骤 5/7: 点击 Transcribe 按钮...');
const transcribeBtn = page.getByRole('button', { name: /transcribe|confirm/i });
await transcribeBtn.click();
console.log('✓ 已点击 Transcribe 按钮');

console.log('⏳ 步骤 6/7: 等待加载动画...');
const skeleton = page.locator('[class*="skeleton"], [class*="loading"]').first();
await skeleton.waitFor({ state: 'visible', timeout: 10000 });
console.log('✓ 开始处理链接（显示加载动画）');
await capture('点击 Transcribe 后 - 显示加载动画', {
  selector: '[class*="skeleton"]'
});

console.log('⏳ 步骤 7/7: 等待结果（最长 10 分钟）...');

const result = await Promise.race([
  page.waitForURL(
    u => u.href.includes('from=official') || u.href.includes('app.notta.ai'),
    { timeout: 600000 }
  ).then(() => 'success'),
  page.locator('[role="dialog"], [class*="dialog"]').waitFor({ state: 'visible', timeout: 600000 }).then(() => 'limit'),
  page.getByText(/error|failed|失败|错误/i).waitFor({ state: 'visible', timeout: 600000 }).then(() => 'error'),
]);

if (result === 'success') {
  console.log('✅ 成功: 已跳转到结果页');
  console.log('结果页 URL:', page.url());
  console.log('⏳ 等待页面加载完成（等待 order/summary 接口）...');
  try {
    await page.waitForResponse(
      response => response.url().includes('/v1/order/summary') && response.status() === 200,
      { timeout: 30000 }
    );
    console.log('✓ 页面数据加载完成');
  } catch (err) {
    console.log('⚠️  等待接口超时，直接等待固定时间');
  }
  await page.waitForTimeout(3000);
  await capture('最终结果 - 成功页面', {
    status: 'success',
    metadata: {
      networkRequest: '/v1/order/summary'
    }
  });
  assert(page.url().includes('from=official'), '应跳转到结果页');
} else if (result === 'limit') {
  console.log('⚠️  达到限制: 显示限制弹窗（IP 限制）');
  const dialogContent = await page.locator('[role="dialog"], [class*="dialog"]').textContent();
  console.log('弹窗内容:', dialogContent.substring(0, 200));
  await capture('最终结果 - 限制弹窗', {
    selector: '[role="dialog"]',
    status: 'warning',
    metadata: {
      elementText: dialogContent ? dialogContent.substring(0, 100) : ''
    }
  });
  const signUpBtn = page.getByRole('link', { name: /sign up/i });
  const hasSignUp = await signUpBtn.count() > 0;
  console.log('是否有注册按钮:', hasSignUp);
  assert(hasSignUp, '限制弹窗应有注册按钮');
  console.log('✅ 限制提示正常显示');
} else if (result === 'error') {
  console.log('❌ 出现错误提示');
  const errorText = await page.getByText(/error|failed|失败|错误/i).first().textContent();
  console.log('错误信息:', errorText);
  await capture('最终结果 - 错误提示', {
    status: 'error',
    metadata: {
      elementText: errorText
    }
  });
  assert(false, '处理链接时出现错误: ' + errorText);
}

console.log("🚀 开始测试: YouTube 视频摘要生成主流程");

console.log("⏳ 步骤 1/10: 加载页面...");
await page.waitForLoadState("networkidle");
console.log("✓ 页面加载完成");

console.log("⏳ 步骤 2/10: 等待表单初始化...");
const youtubeLinkInput = page.getByPlaceholder(/paste.*link.*here/i);
await youtubeLinkInput.waitFor({ state: "visible", timeout: 15000 });
console.log("✓ YouTube 链接输入框已显示");
await capture("初始状态 - 表单加载完成", {
  selector: "getByPlaceholder(/paste.*link.*here/i)",
  status: "success"
});

console.log("⏳ 步骤 3/10: 输入 YouTube 链接...");
const testYoutubeUrl = "https://www.youtube.com/watch?v=dQw4w9WgXcQ";
await youtubeLinkInput.fill(testYoutubeUrl);
console.log("✓ 已输入 YouTube 链接: " + testYoutubeUrl);
await page.waitForTimeout(500);
await capture("输入 YouTube 链接后", {
  selector: "getByPlaceholder(/paste.*link.*here/i)",
  metadata: {
    youtubeUrl: testYoutubeUrl
  }
});

console.log("⏳ 步骤 4/10: 验证链接有效性...");
const invalidMsg = page.locator('text=/invalid.*youtube.*link/i');
const isInvalidVisible = await invalidMsg.isVisible().catch(() => false);
if (isInvalidVisible) {
  console.log("❌ YouTube 链接被标记为无效");
  await capture("链接验证失败", {
    selector: 'text=/invalid.*youtube.*link/i',
    status: "error"
  });
  assert(false, "YouTube 链接应该是有效的");
} else {
  console.log("✓ YouTube 链接验证通过");
}

console.log("⏳ 步骤 5/10: 检查语言选择器...");
const lngSelector = page.locator('button[class*="select_trigger"], button:has-text("English")').first();
await lngSelector.waitFor({ state: "visible", timeout: 10000 });
const currentLng = await lngSelector.textContent();
console.log("✓ 当前选择的语言: " + currentLng.trim());
await capture("语言选择器状态", {
  selector: 'button[class*="select_trigger"]',
  metadata: {
    selectedLanguage: currentLng.trim()
  }
});

console.log("⏳ 步骤 6/10: 查找提交按钮...");
const submitBtn = page.getByRole("button", { name: /generate.*transcript/i });
await submitBtn.waitFor({ state: "visible", timeout: 10000 });
const isBtnDisabled = await submitBtn.evaluate((el) => el.classList.contains("disabled") || el.disabled);
console.log("✓ 提交按钮状态 - 禁用: " + isBtnDisabled);
if (isBtnDisabled) {
  console.log("⚠️  提交按钮被禁用，可能是链接验证失败");
  await capture("提交按钮被禁用", {
    selector: "getByRole('button', { name: /generate.*transcript/i })",
    status: "warning"
  });
}

console.log("⏳ 步骤 7/10: 点击生成摘要按钮...");
await submitBtn.click();
console.log("✓ 已点击生成按钮");

console.log("⏳ 步骤 8/10: 等待加载状态...");
const loadingIcon = page.locator('[class*="loading_icon"]');
try {
  await loadingIcon.waitFor({ state: "visible", timeout: 5000 });
  console.log("✓ 加载图标已显示");
  await capture("生成中 - 显示加载状态", {
    selector: '[class*="loading_icon"]',
    metadata: {
      loadingVisible: true
    }
  });
} catch (err) {
  console.log("⚠️  未检测到加载图标，可能直接显示结果或错误");
}

console.log("⏳ 步骤 9/10: 等待结果（成功/限制/错误）...");
const result = await Promise.race([
  page.locator('iframe[src*="youtube-video-summarizer"]').waitFor({ state: "visible", timeout: 120000 }).then(() => "success"),
  page.locator('[class*="result_page"]').waitFor({ state: "visible", timeout: 120000 }).then(() => "success"),
  page.getByText(/the summary will be ready soon/i).waitFor({ state: "visible", timeout: 120000 }).then(() => "success"),
  page.getByText(/create.*account/i).waitFor({ state: "visible", timeout: 120000 }).then(() => "success"),
  page.locator('[role="dialog"]').waitFor({ state: "visible", timeout: 120000 }).then(() => "dialog"),
  page.getByText(/upgrade.*to.*notta.*pro/i).waitFor({ state: "visible", timeout: 120000 }).then(() => "limit"),
  page.getByText(/invalid.*youtube.*link/i).waitFor({ state: "visible", timeout: 120000 }).then(() => "error")
]);

if (result === "success") {
  console.log("✅ 成功: 摘要生成成功");
  await page.waitForTimeout(2000);

  console.log("⏳ 步骤 10/10: 提取 iframe 信息并验证结果页面...");

  const allIframes = page.locator('iframe');
  const iframeCount = await allIframes.count();
  console.log("✓ 页面中的 iframe 数量: " + iframeCount);

  let iframeSrc = "";
  let iframeId = "";
  if (iframeCount > 0) {
    for (let i = 0; i < iframeCount; i++) {
      const iframe = allIframes.nth(i);
      const src = await iframe.getAttribute("src");
      const id = await iframe.getAttribute("id");
      console.log("  iframe " + (i + 1) + ": src=" + src + ", id=" + id);
      if (src && src.includes("youtube-video-summarizer")) {
        iframeSrc = src;
        iframeId = id || "";
        break;
      }
      if (!iframeSrc && src) {
        iframeSrc = src;
        iframeId = id || "";
      }
    }
  }

  const iframeVisible = await page.locator('iframe[src*="youtube-video-summarizer"]').isVisible().catch(() => false);
  const readySoonVisible = await page.getByText(/the summary will be ready soon/i).isVisible().catch(() => false);
  const createAccountVisible = await page.getByText(/create.*account/i).isVisible().catch(() => false);
  const signUpVisible = await page.getByText(/sign up for free/i).isVisible().catch(() => false);

  console.log("✓ 结果 iframe 可见: " + iframeVisible);
  console.log("✓ Ready Soon 提示可见: " + readySoonVisible);
  console.log("✓ Create Account 按钮可见: " + createAccountVisible);
  console.log("✓ Sign Up 按钮可见: " + signUpVisible);
  console.log("✓ 提取到的 iframe src: " + (iframeSrc || "未找到"));

  await capture("最终结果 - 摘要生成成功", {
    selector: iframeVisible ? 'iframe[src*="youtube-video-summarizer"]' : 'iframe',
    status: "success",
    metadata: {
      resultType: iframeVisible ? "iframe-visible" : "ready-soon-page",
      iframeSrc: iframeSrc || "未找到 iframe",
      iframeId: iframeId || "无ID",
      iframeCount: iframeCount,
      readySoonVisible: readySoonVisible,
      createAccountVisible: createAccountVisible,
      signUpVisible: signUpVisible
    }
  });

  assert(iframeVisible || readySoonVisible || createAccountVisible || signUpVisible || iframeCount > 0, "应该显示结果页面或注册提示")

} else if (result === "dialog" || result === "limit") {
  console.log("⚠️  达到限制或显示升级弹窗");
  await page.waitForTimeout(1000);

  const dialog = page.locator('[role="dialog"]').first();
  const dialogText = await dialog.textContent().catch(() => "");

  await capture("最终结果 - 限制提示弹窗", {
    selector: '[role="dialog"]',
    status: "warning",
    metadata: {
      elementText: dialogText.substring(0, 200)
    }
  });

  console.log("✓ 弹窗内容: " + dialogText.substring(0, 100));
  console.log("⏳ 步骤 10/10: 验证升级链接...");
  const upgradeLink = page.getByRole("link", { name: /upgrade|get.*pro/i });
  const upgradeLinkVisible = await upgradeLink.isVisible().catch(() => false);
  console.log("✓ 升级链接可见: " + upgradeLinkVisible);

} else if (result === "error") {
  console.log("❌ 出现错误提示");
  await page.waitForTimeout(1000);

  const errorDialog = page.locator('[role="dialog"]').first();
  const errorText = await errorDialog.textContent().catch(() => "");

  await capture("最终结果 - 错误提示", {
    selector: '[role="dialog"]',
    status: "error",
    metadata: {
      elementText: errorText.substring(0, 200)
    }
  });

  console.log("✓ 错误信息: " + errorText.substring(0, 100));
  console.log("⚠️  测试完成但出现错误");
}

console.log("✅ 测试完成: YouTube 视频摘要主流程验证完成");
